    if (typeof window.earcut === 'undefined') {
        console.error("earcut.js is not loaded! Cannot split polygon. (Checked window.earcut)");
        return [];
    }

    const originalVertsArray = shape.v;
    const flatVertices = [];
    for (const p of originalVertsArray) {
        flatVertices.push(p[0], p[1]);
    }

    let indices;
    try {
         // --- FIX: Use window.earcut ---
         indices = window.earcut(flatVertices);
    } catch (e) {
        console.error("Earcut failed:", e);
        return [];
    }

    const convexPolys = [];
    for (let i = 0; i < indices.length; i += 3) {
        const i1 = indices[i];
        const i2 = indices[i + 1];
        const i3 = indices[i + 2];
        const v1 = originalVertsArray[i1];
        const v2 = originalVertsArray[i2];
        const v3 = originalVertsArray[i3];
        if (v1 && v2 && v3) {
            convexPolys.push([v1, v2, v3]);
        }
    }
    return convexPolys;
