export function doBoundsOverlap(box1, box2, padding = 0) {
  return (
    box1.minX < box2.maxX + padding &&
    box1.maxX > box2.minX - padding &&
    box1.minY < box2.maxY + padding &&
    box1.maxY > box2.minY - padding
