    // Now iterate the difference result

    const allFinalConvexPieces = [];

    for (const mp of diff) {

      if (!Array.isArray(mp) || mp.length === 0) continue;

      const rawOuter = mp[0];

      if (!Array.isArray(rawOuter) || rawOuter.length < 3) continue;

      let outer = dedupeRing(rawOuter);



      const rawHoles = mp.slice(1).filter(h => Array.isArray(h) && h.length >= 3);

      let holes = rawHoles.map(h => dedupeRing(h)).filter(h => areaOfRing(h) >= MIN_RING_AREA);



      const outerSigned = signedArea(outer);

      holes = holes.map(h => {

        if (outerSigned * signedArea(h) > 0) { h.reverse(); }

        return h;

      });



      // Stitch holes

      let currentOuter = outer;

      for (const h of holes) {

        currentOuter = stitchHoleIntoOuter(currentOuter, h);

      }



      // Dedup again and feed into convex decomposition

      const holeFree = dedupeRing(currentOuter);

      if (areaOfRing(holeFree) < MIN_RING_AREA) continue;


      // --- MODIFICATION: Apply RDP simplification ---
      const polyForSplitting = (epsilon > 0) ? rdpSimplify(holeFree, epsilon) : holeFree;
      if (epsilon > 0) {
        console.log(`[generateTunnel] Simplified polygon from ${holeFree.length} to ${polyForSplitting.length} vertices (epsilon: ${epsilon}).`);
      }
      // --- END MODIFICATION ---

      try {
        // --- MODIFICATION START ---
        // Use the new Earcut-based splitting function
        if (typeof splitAndMergeConvex === "function") {
          console.log(`[generateTunnel] Splitting polygon with ${polyForSplitting.length} vertices...`);
          // Pass in the { v: [...] } format
          const pieces = splitAndMergeConvex({ v: polyForSplitting });

          if (pieces && pieces.length > 0) {
            console.log(`[generateTunnel] Split into ${pieces.length} convex pieces.`);
            // The new function returns arrays of vertices [ [x,y], ... ], 
            // so we wrap them in the { v: ... } object expected by the old logic.
            allFinalConvexPieces.push(...pieces.map(p => ({ v: p })));
          } else {
             console.warn("[generateTunnel] Splitting returned no pieces. Adding raw polygon.");
            allFinalConvexPieces.push({ v: polyForSplitting });
          }
        } else {
          // Fallback to old function if new one isn't loaded
          console.error("[generateTunnel] splitAndMergeConvex function not found! Falling back to old splitConcaveIntoConvex.");
          if (typeof splitConcaveIntoConvex === "function") {
            const pieces = splitConcaveIntoConvex({ v: polyForSplitting });
            if (pieces && pieces.length) {
              allFinalConvexPieces.push(...pieces);
            } else {
              allFinalConvexPieces.push({ v: polyForSplitting });
            }
          } else {
            console.error("[generateTunnel] No split function found. Adding raw polygon.");
            allFinalConvexPieces.push({ v: polyForSplitting });
          }
        }
        // --- MODIFICATION END ---
      } catch (err) {

        console.warn("Splitting function failed; adding raw part:", err);

        allFinalConvexPieces.push({ v: polyForSplitting });

      }

    }



    // Format for Network.createObjectsBatch

    const allTunnelPieces = [];

    for (const piece of allFinalConvexPieces) {

      const abs = piece.v.map(p => ({ x: p[0], y: p[1] }));

      if (abs.length < 3) continue;

      const c = (typeof calculatePolygonCenter === "function") ? calculatePolygonCenter(abs) : { x: 0, y: 0 };

      if (!c || !isFinite(c.x) || !isFinite(c.y)) {

        console.warn("Skipping piece with invalid centroid", piece);

        continue;

      }

      const v = abs.map(p => ({ x: p.x - c.x, y: p.y - c.y }));

      allTunnelPieces.push({

        type: "poly", c, v, a: 0, scale: 1,

        polyType: "death"

      });

    }



    if (allTunnelPieces.length > 0) {
      console.log(`[generateTunnel] Creating ${allTunnelPieces.length} final polygon objects.`);
      if (Network && typeof Network.createObjectsBatch === "function") {

        Network.createObjectsBatch({ objects: allTunnelPieces, isAutoGeneration: true });

      } else {

        console.log("Prepared polygons (not sent):", allTunnelPieces.length);

      }

    } else {

      console.log("[generateTunnel] No final polygons after processing.");

    }



  } catch (err) {

    console.error("generateTunnelFromPath failed:", err);

  }

}



// --- TEST MOUSE DRAWER (kept API and name) ---

export function startPathDrawing_TEST() {

  const canvasElem = (typeof UI !== "undefined" && UI.elems && UI.elems.canvas) ? UI.elems.canvas : (document.querySelector && document.querySelector("canvas"));

  if (!canvasElem) return Promise.reject(new Error("Canvas not available"));



  function simplifyPoints(pts, minDist) {

    if (!pts || pts.length === 0) return [];

    const out = [pts[0]];

    for (let i = 1; i < pts.length; i++) {

      const dx = pts[i].x - out[out.length - 1].x;

      const dy = pts[i].y - out[out.length - 1].y;

      if (Math.hypot(dx, dy) >= minDist) out.push(pts[i]);

    }

    return out;

  }



  function chaikinSmooth(pts, iterations = 1, ratio = 0.25) {

    if (!pts || pts.length < 3) return (pts ? pts.slice() : []);

    let inPts = pts.slice();

    let outPts = [];

    for (let iter = 0; iter < iterations; iter++) {

      outPts = [];

      if (inPts.length > 0) outPts.push(inPts[0]);

      for (let i = 0; i < inPts.length - 1; i++) {

        const p0 = inPts[i];

        const p1 = inPts[i+1];

        const q0x = (1 - ratio) * p0.x + ratio * p1.x;

        const q0y = (1 - ratio) * p0.y + ratio * p1.y;

        const q1x = ratio * p0.x + (1 - ratio) * p1.x;

        const q1y = ratio * p0.y + (1 - ratio) * p1.y;

        outPts.push({ x: q0x, y: q0y });

        outPts.push({ x: q1x, y: q1y });

      }

      if (inPts.length > 1) outPts.push(inPts[inPts.length - 1]);

      inPts = outPts;

    }

    return outPts;

  }



  return new Promise((resolve, reject) => {

    const points = [];

    let drawing = false;



    function toLocal(evt) {

      const rect = canvasElem.getBoundingClientRect();

      return { x: evt.clientX - rect.left, y: evt.clientY - rect.top };

    }



    function onDown(e) {

      if (e.button !== 0) return;

      drawing = true;

      points.length = 0;

      points.push(toLocal(e));

      window.addEventListener("mousemove", onMove);

      window.addEventListener("mouseup", onUp);

    }

    function onMove(e) {

      if (!drawing) return;

      points.push(toLocal(e));

    }

    function onUp(e) {

      if (!drawing) return;

      drawing = false;

      window.removeEventListener("mousemove", onMove);

      window.removeEventListener("mouseup", onUp);

      cleanupListeners();



      const simplified = simplifyPoints(points, 2);

      if (simplified.length < 2) return reject(new Error("Not enough points drawn"));

      const path = chaikinSmooth(simplified, 2);

      resolve(path);

    }

    function onKey(e) {

      if (e.key === "Escape") {

        cleanupListeners();

        reject(new Error("Drawing cancelled"));

      }

    }

    function cleanupListeners() {

      canvasElem.removeEventListener("mousedown", onDown);

      window.removeEventListener("keydown", onKey);

      window.removeEventListener("mousemove", onMove);

      window.removeEventListener("mouseup", onUp);

    }



    canvasElem.addEventListener("mousedown", onDown);

    window.addEventListener("keydown", onKey);



    if (UI && UI.showToast) UI.showToast("[TEST] Draw a path. Release to generate corridors. Esc to cancel.");

  });

}

