/* ai-generator-map.js
   Generates a flat-top polygon and simulates a complex, configurable maneuver.
   - Moves to the platform edge with predictive stopping.
   - Jumps at a random point in the run (configurable).
   - Jump height and fall speed are randomized (configurable).
   - Moves the Cap Zone to the final stopping position.
   - **REVISED**: Generates two separate death-polygon "corridors" that
     flank the simulated path, using mitered normals to prevent self-intersection.
*/

import State from "./state.js";
import UI from "./ui.js";
import {
  PhysicsPlayer,
  PhysicsMap,
  parseStateObjects,
  PHYSICS_SETTINGS,
} from "./ai-generator-utils.js";
import {
  splitAndFormatPolygons,
  randomFloat,
  randomInt,
  randChoice,
  getRandomType,
  computePathLengths, // We still use this to sample the path
  samplePointAndTangent, // We still use this to get points
  polygonSelfIntersects,
  // --- NEW VECTOR IMPORTS ---
  v,
  add,
  sub,
  scale,
  normalize,
  perp,
} from "./utils-client.js";

// --- Config (tweakable) ---
const CONFIG = {
  CANVAS_PADDING: 20,
  TOP_MARGIN: 6,
  POLYGON_TOP_WIDTH: 140,
  POLYGON_DEPTH: 44,
  MAX_SIM_SEC: 10,
  STOP_TOLERANCE: 0.1,

  // --- Maneuver Config ---
  MANEUVER_DISTANCE_RANGE_DIAMETERS: [1.0, 10.0],
  JUMP_PROBABILITY: 1.0, // (0.0 to 1.0)
  // (Portion of run, e.g., 0.1=10% thru, 0.9=90% thru)
  JUMP_INITIATION_RANGE: [0.1, 0.9],

  // --- Jump Height Config ---
  JUMP_HEIGHT_WEIGHTS: {
    tap: 1,
    mid: 1,
    full: 1,
  },
  // Jump hold settings:
  // - tap: short fixed hold
  // - mid: randomized hold (only case with randomness)
  // - full: -1 means hold until apex
  JUMP_HOLD: {
    tap: 0.05,
    midRange: [0.08, 0.22],
    full: -1,
  },

  // --- Fall Speed Config ---
  FALL_INPUT_WEIGHTS: {
    up: 1,
    none: 1,
    down: 1,
  },

  // --- Path Tunnel Config ---
  PATH_DEATH_TUNNEL: {
    enabled: true,
    padding: 10,
    thickness: 15,
    polyType: "death",
    sampleCount: 30,
    stepJitterFactor: 0.1, // Jitter for *sampling* is fine
    minTriggerLength: 50,
  },
};

// --- End Config ---

// --- Polygon Generation (Unchanged) ---
function makeFlatTopPoly(canvasW, canvasH) {
  const topWidth = CONFIG.POLYGON_TOP_WIDTH;
  const depth = CONFIG.POLYGON_DEPTH;
  const half = topWidth / 2;

  const topY = randomFloat(
    CONFIG.CANVAS_PADDING,
    canvasH - CONFIG.CANVAS_PADDING - depth,
  );
  const cx = randomFloat(
    CONFIG.CANVAS_PADDING + half,
    canvasW - CONFIG.CANVAS_PADDING - half,
  );

  const v_arr = [];
  v_arr.push({ x: -half, y: 0 }); // v[0]: left top
  v_arr.push({ x: half, y: 0 }); // v[1]: right top

  const numExtraVerts = randomInt(2, 5);
  const points = [];
  for (let i = 0; i < numExtraVerts; i++) {
    const angle =
      (Math.PI * (i + 0.5 + randomFloat(-0.1, 0.1))) / (numExtraVerts + 1);
    const radius = randomFloat(half * 0.5, half + depth);
    points.push({
      x: Math.cos(angle) * radius,
      y: Math.sin(angle) * radius + randomFloat(0, depth * 0.2),
    });
  }
  points.sort((a, b) => b.x - a.x);
  v_arr.push(...points);

  return {
    id: "gen-poly-" + Date.now(),
    type: "poly",
    v: v_arr,
    c: { x: cx, y: topY },
    a: 0,
    scale: 1,
    polyType: "none",
  };
}

// --- Simulation Logic (Unchanged) ---
function computeTopSegment(poly) {
  const c = poly.c;
  const v0 = poly.v[0];
  const v1 = poly.v[1];
  const p1 = { x: c.x + v0.x, y: c.y + v0.y };
  const p2 = { x: c.x + v1.x, y: c.y + v1.y };
  return {
    leftX: Math.min(p1.x, p2.x),
    rightX: Math.max(p1.x, p2.x),
    y: p1.y,
  };
}

function placeSpawnOnPoly(poly) {
  const top = computeTopSegment(poly);
  const currentSpawn = State.get("spawnCircle");
  const diameter = currentSpawn?.diameter || 12;
  const minX = top.leftX + diameter;
  const maxX = top.rightX - diameter;
  let cx = (minX + maxX) / 2;
  if (minX < maxX) {
    cx = randomFloat(minX, maxX);
  }
  const spawnY = top.y - diameter / 2 - CONFIG.TOP_MARGIN;
  State.set("spawnCircle", { ...currentSpawn, x: cx, y: spawnY });
}

function injectPolyToState(poly) {
  State.set("objects", [poly]);
}

function predictStoppingDistance(currentPlayer, map) {
  const ghostPlayer = new PhysicsPlayer(
    currentPlayer.pos.x,
    currentPlayer.pos.y,
    currentPlayer.radius,
  );
  ghostPlayer.vel = { ...currentPlayer.vel };
  ghostPlayer.mass = currentPlayer.mass;

  let distance = 0;
  const input = { up: false, down: false, left: false, right: false };
  const initialDir = Math.sign(ghostPlayer.vel.x);
  if (initialDir === 0) return 0;

  if (initialDir === 1) input.left = true;
  else input.right = true;

  const maxBrakeSteps = Math.ceil(5 / PHYSICS_SETTINGS.TIME_STEP);
  for (let i = 0; i < maxBrakeSteps; i++) {
    const startX = ghostPlayer.pos.x;
    ghostPlayer.update(input, map);
    distance += Math.abs(ghostPlayer.pos.x - startX);
    if (
      Math.sign(ghostPlayer.vel.x) !== initialDir ||
      Math.abs(ghostPlayer.vel.x) < CONFIG.STOP_TOLERANCE
    ) {
      return distance;
    }
  }
  return distance;
}

function getRandomJumpDuration() {
  const type = getRandomType(CONFIG.JUMP_HEIGHT_WEIGHTS);

  if (type === "tap") {
    return CONFIG.JUMP_HOLD && typeof CONFIG.JUMP_HOLD.tap === "number"
      ? CONFIG.JUMP_HOLD.tap
      : 0.05;
  }

  if (type === "mid") {
    const range = CONFIG.JUMP_HOLD?.midRange || [0.08, 0.22];
    return randomFloat(range[0], range[1]);
  }

  if (type === "full") {
    return CONFIG.JUMP_HOLD && typeof CONFIG.JUMP_HOLD.full === "number"
      ? CONFIG.JUMP_HOLD.full
      : -1;
  }

  return 0.05;
}

function simulateManeuver(spawn, poly, params) {
  const dt = PHYSICS_SETTINGS.TIME_STEP;
  const maxSteps = Math.ceil(CONFIG.MAX_SIM_SEC / dt);
  const map = new PhysicsMap(parseStateObjects([poly]), {
    x: spawn.x,
    y: spawn.y,
  });
  const player = new PhysicsPlayer(spawn.x, spawn.y, spawn.diameter / 2);

  const maneuverLengthDiameters = randomFloat(
    CONFIG.MANEUVER_DISTANCE_RANGE_DIAMETERS[0],
    CONFIG.MANEUVER_DISTANCE_RANGE_DIAMETERS[1],
  );
  const maneuverLengthPixels = maneuverLengthDiameters * spawn.diameter;
  const targetX = spawn.x + maneuverLengthPixels * params.dir;
  const topEdge = computeTopSegment(poly);

  const simState = {
    horizontal: "RUNNING",
    vertical: "GROUNDED",
    willJump: Math.random() < CONFIG.JUMP_PROBABILITY,
    hasJumped: false,
    jumpHoldRemaining: 0,
    currentFallBehavior: null,
    targetX: targetX,
    jumpInitiationX:
      spawn.x +
      (targetX - spawn.x) *
        randomFloat(
          CONFIG.JUMP_INITIATION_RANGE[0],
          CONFIG.JUMP_INITIATION_RANGE[1],
        ),
  };

  const traj = [];

  for (let step = 0; step < maxSteps; step++) {
    const input = { up: false, down: false, left: false, right: false };
    const wasGrounded = player.isGrounded;

    // --- 1. HORIZONTAL STATE ---
    if (simState.horizontal === "RUNNING") {
      input.right = params.dir === 1;
      input.left = params.dir === -1;
      const stoppingDist = predictStoppingDistance(player, map);
      const distToTarget = Math.abs(simState.targetX - player.pos.x);
      if (distToTarget <= stoppingDist) {
        simState.horizontal = "STOPPING";
      }
    } else if (simState.horizontal === "STOPPING") {
      if (player.vel.x > CONFIG.STOP_TOLERANCE) input.left = true;
      else if (player.vel.x < -CONFIG.STOP_TOLERANCE) input.right = true;
      else simState.horizontal = "STOPPED";
    }

    // --- 2. JUMP TRIGGER ---
    if (simState.willJump && !simState.hasJumped && wasGrounded) {
      const passedTrigger =
        params.dir === 1
          ? player.pos.x >= simState.jumpInitiationX
          : player.pos.x <= simState.jumpInitiationX;

      if (passedTrigger) {
        simState.hasJumped = true;
        simState.jumpHoldRemaining = getRandomJumpDuration();
        input.up = true;
        simState.vertical = "JUMP_ASCEND";
      }
    }

    const VY_EPS = 0.02;

    // --- 3. VERTICAL STATE ---
    if (simState.vertical === "JUMP_ASCEND") {
      if (simState.jumpHoldRemaining > 0) {
        input.up = true;
        simState.jumpHoldRemaining -= dt;
      } else if (simState.jumpHoldRemaining === -1 && player.vel.y < VY_EPS) {
        input.up = true;
      } else {
        simState.jumpHoldRemaining = 0;
        simState.vertical = "FALLING";
      }
    } else if (simState.vertical === "FALLING") {
      if (simState.currentFallBehavior === null) {
        simState.currentFallBehavior = getRandomType(CONFIG.FALL_INPUT_WEIGHTS);
      }
      if (simState.currentFallBehavior === "up" && player.vel.y >= VY_EPS) {
        const ghost = new PhysicsPlayer(
          player.pos.x,
          player.pos.y,
          player.radius,
        );
        ghost.vel = { ...player.vel };
        ghost.mass = player.mass;
        const ghostInput = { ...input, up: false, down: false };
        ghost.update(ghostInput, map);
        if (!ghost.isGrounded) {
          input.up = true;
        }
      } else if (simState.currentFallBehavior === "down") {
        input.down = true;
      }
    }

    // --- 4. UPDATE ---
    const res = player.update(input, map);
    traj.push({ x: player.pos.x, y: player.pos.y });

    // --- 5. POST-UPDATE STATE ---
    const isNowGrounded = player.isGrounded;
    if (isNowGrounded) {
      simState.vertical = "GROUNDED";
      simState.currentFallBehavior = null;
    } else if (wasGrounded) {
      if (simState.vertical !== "JUMP_ASCEND") {
        simState.vertical = "FALLING";
      }
    }

    // --- 6. END CONDITION ---
    const isHorizontallyStopped = simState.horizontal === "STOPPED";
    if (
      (simState.willJump && isHorizontallyStopped && isNowGrounded) ||
      (!simState.willJump && isHorizontallyStopped)
    ) {
      break;
    }

    // --- 7. Fail-safes ---
    if (res === "DIED" || player.pos.y > topEdge.y + 100) break;
  }

  return traj;
}

function playbackTrajectory(traj) {
  let i = 0;
  function step() {
    if (i >= traj.length) {
      setTimeout(() => State.set("simulationPreview", null), 500);
      return;
    }
    const p = traj[i++];
    State.set("simulationPreview", {
      x: p.x,
      y: p.y,
      radius: State.get("spawnCircle")?.diameter / 2 || 6,
    });
    requestAnimationFrame(step);
  }
  requestAnimationFrame(step);
}

function generatePathCorridorPolygons(path, playerRadius, cfg, segLengths, total) {
  if (total <= 0 || !Array.isArray(path) || path.length < 2) return null;

  // --- CONFIG (from cfg) ---
  const SAMPLE_COUNT = Math.max(2, Math.min(cfg.sampleCount || 30, path.length));
  const OFFSET_INNER = playerRadius + (cfg.padding || 0);
  const OFFSET_OUTER = OFFSET_INNER + (cfg.thickness || 10);
  // Epsilon value to prevent division by zero and check distances
  const EPS = 0.1;

  // --- 1. Sample the Path ---
  // Create a clean list of points from the trajectory
  const rawPoints = [];
  for (let i = 0; i < SAMPLE_COUNT; i++) {
    const t = i / (SAMPLE_COUNT - 1); // Normalized 0-1
    const { p } = samplePointAndTangent(path, t, segLengths, total);
    rawPoints.push(p);
  }

  // Filter out duplicate adjacent points (from simulation stopping)
  const pointsToUse = [rawPoints[0]];
  for (let i = 1; i < rawPoints.length; i++) {
    const p1 = pointsToUse[pointsToUse.length - 1];
    const p2 = rawPoints[i];
    if (Math.hypot(p1.x - p2.x, p1.y - p2.y) > EPS) {
      pointsToUse.push(p2);
    }
  }

  if (pointsToUse.length < 2) {
    console.warn("Path corridor: Not enough unique points after filtering.");
    return null;
  }

  // --- 2. Generate Initial "Rails" ---
  // These rails might be wrong at corners, but we fix them next.
  const innerLeft = [];
  const outerLeft = [];
  const innerRight = [];
  const outerRight = [];

  const m = pointsToUse.length;
  let lastGoodTangent = v(1, 0); // Failsafe for the very first point

  for (let i = 0; i < m; i++) {
    const p = pointsToUse[i];
    let tangent;

    if (i === 0) {
      tangent = normalize(sub(pointsToUse[i + 1], p));
    } else if (i === m - 1) {
      tangent = normalize(sub(p, pointsToUse[i - 1]));
    } else {
      // "Miter" normal: Average the incoming and outgoing vectors
      const v_prev = normalize(sub(p, pointsToUse[i - 1]));
      const v_next = normalize(sub(pointsToUse[i + 1], p));
      tangent = normalize(add(v_prev, v_next));
    }

    // Failsafe for (0,0) tangents
    if (Math.hypot(tangent.x, tangent.y) < EPS) {
      tangent = lastGoodTangent;
    } else {
      lastGoodTangent = tangent;
    }

    const normal = perp(tangent); // 90-degree CCW rotation

    // Add points to all four rails
    innerLeft.push(add(p, scale(normal, OFFSET_INNER)));
    outerLeft.push(add(p, scale(normal, OFFSET_OUTER)));
    innerRight.push(add(p, scale(normal, -OFFSET_INNER)));
    outerRight.push(add(p, scale(normal, -OFFSET_OUTER)));
  }

  // --- 3. Correction Pass (The "Push-Out" Fix) ---
  // This is the most important step. We check every generated point
  // against the *original* trajectory.

  // Helper to find the closest point on the original path
  function getClosestPointOnPath(pt) {
    let minDistSq = Infinity;
    let closestPt = path[0];
    let pushVector = v(0, 0);

    for (let i = 0; i < path.length - 1; i++) {
      const a = path[i];
      const b = path[i + 1];

      const vAB = sub(b, a);
      const vAP = sub(pt, a);
      const lenAB = Math.hypot(vAB.x, vAB.y);

      if (lenAB < EPS) continue; // Skip zero-length segments

      // Project p onto the line AB
      const t = (vAP.x * vAB.x + vAP.y * vAB.y) / (lenAB * lenAB);

      let projPt;
      if (t < 0) projPt = a;
      else if (t > 1) projPt = b;
      else projPt = add(a, scale(vAB, t));

      const distSq = (pt.x - projPt.x)**2 + (pt.y - projPt.y)**2;

      if (distSq < minDistSq) {
        minDistSq = distSq;
        closestPt = projPt;
      }
    }

    // The vector to push the point away
    const dist = Math.sqrt(minDistSq);
    if (dist < EPS) { // Point is *on* the path, push in a default direction
        pushVector = v(0, -1); 
    } else {
        pushVector = normalize(sub(pt, closestPt));
    }

    return { dist: dist, pushVector: pushVector };
  }

  // Correct the Left Rail
  for (let i = 0; i < innerLeft.length; i++) {
    const { dist, pushVector } = getClosestPointOnPath(innerLeft[i]);

    if (dist < OFFSET_INNER - EPS) {
      const pushAmount = (OFFSET_INNER - dist);
      const push = scale(pushVector, pushAmount);
      // Push *both* inner and outer points to maintain thickness
      innerLeft[i] = add(innerLeft[i], push);
      outerLeft[i] = add(outerLeft[i], push);
    }
  }

  // Correct the Right Rail
  for (let i = 0; i < innerRight.length; i++) {
    const { dist, pushVector } = getClosestPointOnPath(innerRight[i]);

    if (dist < OFFSET_INNER - EPS) {
      const pushAmount = (OFFSET_INNER - dist);
      const push = scale(pushVector, pushAmount);
      // Push *both* inner and outer points
      innerRight[i] = add(innerRight[i], push);
      outerRight[i] = add(outerRight[i], push);
    }
  }

  // --- 4. Final Assembly ---
  const polyLeft = [...innerLeft, ...outerLeft.reverse()];
  const polyRight = [...innerRight, ...outerRight.reverse()];

  // 5. Final safety check (which should now pass)
  if (polygonSelfIntersects(polyLeft)) {
    console.warn("Generated left death corridor self-intersects (after fix), discarding.");
    return null;
  }
  if (polygonSelfIntersects(polyRight)) {
    console.warn("Generated right death corridor self-intersects (after fix), discarding.");
    return null;
  }

  return [polyLeft, polyRight];
}


/**
 * Main function called by handlers.js to generate the map.
 */
export function generateParkourMap() {
  const canvas = UI.elems.canvas || { width: 800, height: 600 };

  // 1. Create polygon
  const poly = makeFlatTopPoly(canvas.width, canvas.height);
  injectPolyToState(poly);

  // 2. Place spawn
  placeSpawnOnPoly(poly);
  const spawn = State.get("spawnCircle");
  if (!spawn) {
    console.error("Spawn not placed");
    return;
  }

  // 3. Set simulation parameters
  const simParams = {
    dir: randChoice([-1, 1]),
  };

  // 4. Run simulation
  const trajectory = simulateManeuver(spawn, poly, simParams);

  // 5. Play back & Set Cap Zone
  if (trajectory && trajectory.length > 0) {
    playbackTrajectory(trajectory);

    const finalPos = trajectory[trajectory.length - 1];
    const cz = State.get("capZone") || { width: 30, height: 18.5 };

    State.set("capZone", {
      ...cz,
      x: finalPos.x - cz.width / 2,
      y: finalPos.y - cz.height / 2,
    });

    // --- **MODIFIED**: Generate Death Corridors ---
    const { PATH_DEATH_TUNNEL } = CONFIG;
    const { segLengths, total } = computePathLengths(trajectory);

    if (
      PATH_DEATH_TUNNEL.enabled &&
      total >= PATH_DEATH_TUNNEL.minTriggerLength
    ) {
      const playerRadius = spawn.diameter / 2;
      const corridorPolygons = generatePathCorridorPolygons(
        trajectory,
        playerRadius,
        PATH_DEATH_TUNNEL,
        segLengths,
        total,
      );

      if (corridorPolygons && corridorPolygons.length > 0) {
        const allTunnelPieces = [];
        for (const poly of corridorPolygons) {
          const pieces = splitAndFormatPolygons(
            poly,
            PATH_DEATH_TUNNEL.polyType,
          );
          allTunnelPieces.push(...pieces);
        }

        if (allTunnelPieces.length > 0) {
          const existingObjects = State.get("objects") || [];
          State.set("objects", [...existingObjects, ...allTunnelPieces]);
        }
      }
    }
  } else {
    console.warn("Simulation produced no trajectory.");
    State.set("simulationPreview", null);
  }
}

public/app.js.content:
/**
 * app.js - Client-Side Orchestrator
 */
import UI from "./ui.js";
import State from "./state.js";
import Canvas from "./canvas.js";
import * as Network from "./network.js";
import AdminUI from "./admin.js"; // Add this
import { bindUIEvents } from "./handlers.js";
import { showToast, getSpawnDiameter } from "./utils-client.js";

function main() {
  UI.init();
  AdminUI.init(); // Add this
  bindUIEvents();
  bindNetworkEvents();
  watchStateChanges();
  Canvas.draw();
}

// Single source of truth: if this is not null, a notification session is active.
let notificationInterval = null;
const originalTitle = document.title;
const notificationTitle = "💬 New Message!";

const notificationSound = new Audio("/sounds/chat.wav");
notificationSound.preload = "auto";
notificationSound.volume = 0.5;

/**
 * Play a short join sound if any NEW player (other than this client) appears
 * in `newPlayers` that wasn't in `prevPlayers`.
 */
function playJoinSoundIfNew(prevPlayers = [], newPlayers = []) {
  try {
    if (!State.get("isNotificationSoundOn")) {
      return;
    }
    const prevIds = new Set((prevPlayers || []).map((p) => p.id));
    const myId = State.get("socketId");
    const newJoin = (newPlayers || []).some(
      (p) => p?.id && !prevIds.has(p.id) && p.id !== myId,
    );
    if (!newJoin) return;
    notificationSound.currentTime = 0;
    notificationSound.play().catch(() => {
      /* ignore play failures (auto-play policy, etc.) */
    });
  } catch (e) {
    console.error("playJoinSoundIfNew error:", e);
  }
}

function bindNetworkEvents() {
  Network.onConnectWithId((id) => State.set("socketId", id));

  Network.onLobbyFull(() => showToast("Sorry, the lobby is full.", true));
  Network.onLobbyNameTaken(() => showToast("Name already taken!", true));

  Network.onLobbyUpdate(({ players, gameActive }) => {
    const prevPlayers = State.get("players") || [];
    playJoinSoundIfNew(prevPlayers, players || []);

    State.set("players", players || []);
    UI.updateLobby(players || []);
    const me = (players || []).find((p) => p.id === State.get("socketId"));
    if (UI.elems.readyCheckbox) UI.elems.readyCheckbox.disabled = !me;
    State.set("gameActive", !!gameActive);
  });

  Network.onGameInProgress(() =>
    UI.showLobbyMessage("Game in progress. Set 'Ready' to join."),
  );
  Network.onStartGame(initializeGameView);
  Network.onGameSnapshot(initializeGameView);
  Network.onGameUpdate(({ players, votes, totalParticipants }) => {
    const prevPlayers = State.get("players") || [];
    playJoinSoundIfNew(prevPlayers, players || []);

    UI.updatePlayers(players || []);
    UI.setVote(votes ?? 0, totalParticipants ?? 0);
  });
  Network.onEndGame(({ reason }) => {
    State.set("gameActive", false);
    if (UI.elems && UI.elems.readyCheckbox) {
      UI.elems.readyCheckbox.checked = false;
    }
    UI.hide("canvasWrap");
    UI.show("home");
    UI.setEndReason(
      reason === "voted" ? "All players voted to end." : "All players left.",
    );
    UI.show("gameEndPopup");
    UI.showLobbyMessage("Drawing will start when 2 players are ready.");
  });
  Network.onObjectCreated((newObject) => {
    State.set("objects", [...State.get("objects"), newObject]);
    if (newObject.playerId === State.get("socketId")) {
      State.set("selectedObjectIds", [newObject.id]);
    }
  });

  Network.onObjectsCreatedBatch((newObjects) => {
    if (Array.isArray(newObjects) && newObjects.length > 0) {
      State.set("objects", [...State.get("objects"), ...newObjects]);

      const myId = State.get("socketId");
      const myNewObjectIds = newObjects
        .filter((o) => o.playerId === myId)
        .map((o) => o.id);

      if (myNewObjectIds.length > 0) {
        State.set("selectedObjectIds", myNewObjectIds);
      }
    }
  });

  // ---------- app.js (notification block) ----------

  function startTitleFlashing() {
    // This function is now simpler because the guard is in the caller.
    let showOriginal = false;
    notificationInterval = setInterval(() => {
      document.title = showOriginal ? originalTitle : notificationTitle;
      showOriginal = !showOriginal;
    }, 1000);
  }

  function stopTitleFlashingAndRestoreTitle() {
    if (notificationInterval) {
      clearInterval(notificationInterval);
      notificationInterval = null;
    }
    document.title = originalTitle;
  }

  function startNotificationIfHidden() {
    // 1. Only run if the tab is hidden AND a notification is not already active.
    //    This check now prevents all race conditions and duplicate sounds.
    if (!document.hidden || notificationInterval) {
      return;
    }

    // 2. Start the notification session. This immediately sets `notificationInterval`,
    //    preventing this function from running again until the user returns.
    startTitleFlashing();

    // 3. Check if sound is enabled. With simpler logic, this check now works reliably.
    if (!State.get("isNotificationSoundOn")) {
      return;
    }

    // 4. Play the sound.
    try {
      notificationSound.currentTime = 0; // Rewind the sound to the beginning
      notificationSound.play().catch((err) => {
        console.error("Notification audio play failed:", err);
      });
    } catch (e) {
      console.error("Error trying to play notification sound:", e);
    }
  }

  // This handler remains unchanged but will now behave correctly.
  Network.onChatMessage((msg) => {
    UI.appendChat(msg);
    startNotificationIfHidden();
  });

  function resetNotificationsForNextSession() {
    // When the user returns, stop the flashing and sound to reset the state.
    stopTitleFlashingAndRestoreTitle();
    try {
      notificationSound.pause();
      notificationSound.currentTime = 0;
    } catch (e) {
      // Ignore errors, e.g., if the sound was never played.
    }
  }

  // These event listeners also remain unchanged.
  document.addEventListener("visibilitychange", () => {
    if (!document.hidden) {
      resetNotificationsForNextSession();
    }
  });
  window.addEventListener("focus", resetNotificationsForNextSession);

  Network.onObjectUpdated((updatedObject) => {
    const objects = State.get("objects").map((o) =>
      o.id === updatedObject.id ? updatedObject : o,
    );
    State.set("objects", objects);
    // Only update editor if this is the *only* selected object
    const selectedIds = State.get("selectedObjectIds");
    if (selectedIds.length === 1 && selectedIds[0] === updatedObject.id) {
      if (updatedObject.type === "line")
        UI.updateLineEditorValues(updatedObject);
      if (updatedObject.type === "poly")
        UI.updatePolygonEditorValues(updatedObject);
    }
  });

  Network.onObjectDeleted(({ id }) => {
    State.set(
      "objects",
      State.get("objects").filter((o) => o.id !== id),
    );
    State.removeSelectedObjectId(id);
  });

  Network.onObjectsReordered((reorderedObjects) => {
    if (Array.isArray(reorderedObjects)) {
      reorderedObjects.forEach((obj) => {
        if (obj.type === "poly") {
          console.log("Poly object:", obj, "scale:", obj.scale);
        } else {
          console.log("Object:", obj);
        }
      });
    }
    State.set("objects", reorderedObjects || []);
  });

  Network.onSpawnCircleUpdate((spawnCircle) =>
    State.set("spawnCircle", spawnCircle),
  );
  Network.onCapZoneUpdate((capZone) => State.set("capZone", capZone));
  Network.onMapSizeUpdate((mapSize) => {
    State.set("mapSize", mapSize);
    if (UI.elems.spawnSizeSlider) UI.elems.spawnSizeSlider.value = mapSize;
    if (UI.elems.spawnSizeValue) UI.elems.spawnSizeValue.innerText = mapSize;
  });
  Network.onChatError((errorMsg) => showToast(errorMsg, true));
  Network.onClearChat(() => UI.clearChat());

  Network.onKicked(({ reason }) => {
    alert(`${reason}`);
    window.location.reload();
  });

  Network.onLobbyJoinFail(({ message }) => {
    showToast(message, true);
  });

  Network.onAdminStateUpdate((state) => {
    UI.toggleLobbyPasswordInput(state.hasLobbyPassword);
    AdminUI.handleStateUpdate(state);
  });

  Network.onAdminLoginSuccess((state) => {
    showToast("Admin login successful.");
    AdminUI.handleLoginSuccess(state);
  });

  Network.onAdminLoginFail(({ message }) => {
    showToast(message, true);
  });

  // MODIFY onEndGame to include admin reason
  Network.onEndGame(({ reason }) => {
    State.set("gameActive", false);
    if (UI.elems && UI.elems.readyCheckbox) {
      UI.elems.readyCheckbox.checked = false;
    }
    UI.hide("canvasWrap");
    UI.show("home");
    let endReasonText = "All players left.";
    if (reason === "voted") endReasonText = "All players voted to end.";
    if (reason === "admin_forced")
      endReasonText = "Drawing was ended by an admin.";
    UI.setEndReason(endReasonText);
    UI.show("gameEndPopup");
    UI.showLobbyMessage("Drawing will start when 2 players are ready.");
  });

  Network.onColorsUpdated((colors) => {
    State.set("colors", colors);
  });
}

function watchStateChanges() {
  let drawPending = false;
  const scheduleDraw = () => {
    if (drawPending) return;
    drawPending = true;
    requestAnimationFrame(() => {
      Canvas.draw();
      drawPending = false;
    });
  };

  State.onChange((key) => {
    const visualKeys = [
      "objects",
      "drawingShape",
      "draggingPreview",
      "capZone",
      "spawnCircle",
      "selectedObjectIds",
      "hideUsernames",
      "selectionBox",
      "colors",
      "simulationPreview", // <-- ADD THIS
    ];
    if (visualKeys.includes(key)) scheduleDraw();

    switch (key) {
      case "selectedObjectIds":
        const selectedIds = State.get(key);
        const selectedObjects = State.get("objects").filter((o) =>
          selectedIds.includes(o.id),
        );
        UI.setObjectEditorVisible(selectedObjects);
        break;
      case "mapSize":
        const spawn = State.get("spawnCircle");
        if (spawn)
          State.set("spawnCircle", {
            ...spawn,
            diameter: getSpawnDiameter(State.get(key)),
          });
        break;
      case "colors": 
        UI.updateColorIndicators(State.get(key));
        break;
    }
  });
}

function initializeGameView(payload = {}) {
  const myId = State.get("socketId");
  const isParticipant = (payload.players || []).some((p) => p.id === myId);

  if (Array.isArray(payload.players) && !isParticipant) {
    return;
  }

  UI.clearChat();
  State.set("hideUsernames", false);
  if (UI.elems.hideUsernamesCheckbox)
    UI.elems.hideUsernamesCheckbox.checked = false;
  if (UI.elems.voteCheckbox) UI.elems.voteCheckbox.checked = false;

  State.set("gameActive", true);
  State.set("objects", payload.objects || []);
  State.set("players", payload.players || []);
  State.set("capZone", payload.capZone);
  State.set("spawnCircle", payload.spawnCircle);
  State.set("mapSize", payload.mapSize ?? 9);
  State.set("colors", payload.colors); 

  UI.hide("home");
  UI.show("canvasWrap");
  UI.updatePlayers(payload.players || []);
}

document.addEventListener("DOMContentLoaded", main);

public/style.css.content:
/* Globals & Variables */
:root {
  /* Canvas sizing */
  --canvas-width: 750px;
  --canvas-height: 500px;
  /* Layout spacing */
  --panel-gap: 1rem;
  /* Font sizes */
  --left-panel-font-size: 13px;
  --home-font-size: 16px;
  /* Color tokens */
  --bg: #121212;
  --panel-bg: #1f1f1f;
  --card-bg: #222;
  --muted-border: #333;
  --accent: #d2691e;
  --font-family: "Lexend", sans-serif;
  --status-ready: #28a745;
  --status-not-ready: #dc3545;
  --status-in-game: #ffc107;
}

/* Reset */
* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html,
body {
  height: 100%;
}

body {
  font-family: var(--font-family);
  background: var(--bg);
  color: #eee;
  display: flex;
  justify-content: center;
  align-items: center;
  min-height: 100vh;
}

/* Utility Classes */
.hidden {
  display: none !important;
}

/* Component Standardization */
.btn {
  font-family: var(--font-family);
  font-size: 14px;
  padding: 0.6rem 1.2rem;
  background: #333;
  color: #eee;
  border: none;
  border-radius: 5px;
  font-weight: 600;
  cursor: pointer;
  transition: background-color 0.2s ease;
}
.btn:hover {
  background: #444;
}
.btn:disabled {
  opacity: 0.6;
  cursor: not-allowed;
}
.btn.btn-small {
  font-size: 13px;
  padding: 0.45rem 0.85rem;
  width: fit-content;
}
/* Icon-only button adjustment */
.btn.btn-icon {
  padding: 0.3rem;     /* tighter padding around the icon */
  width: 2rem;         /* square shape */
  height: 1.6rem;
  display: flex;       /* center the emoji/icon */
  align-items: center;
  justify-content: center;
  font-size: 1rem;   /* adjust icon size */
  margin-top: 0.5rem;
  align-self: flex-end; /* pushes it down to baseline with Send */

}


input[type="text"],
input[type="number"], 
select {
  font-family: var(--font-family);
  padding: 0.5rem;
  border-radius: 4px;
  border: 1px solid #444;
  background: #1e1e1e;
  color: #eee;
  font-size: 14px;
  width: 100%;
}

/* Optional: Add a clean focus style for all inputs */
input[type="text"]:focus,
input[type="number"]:focus,
select:focus {
  border-color: #708090; /* A subtle accent color */
  box-shadow: 0 0 5px rgba(112, 128, 144, 0.5);
  outline: none;
}

select {
  text-align: center;
  text-align-last: center;
}
select:disabled {
  opacity: 0.6;
  cursor: not-allowed;
}

/* Scrollbar Standardization */
.control-box::-webkit-scrollbar,
#chatMessages::-webkit-scrollbar,
.tips-list::-webkit-scrollbar,
.player-list::-webkit-scrollbar {
  width: 7px;
}
.control-box::-webkit-scrollbar-thumb,
#chatMessages::-webkit-scrollbar-thumb,
.tips-list::-webkit-scrollbar-thumb,
.player-list::-webkit-scrollbar-thumb {
  background: #444;
  border-radius: 4px;
}
.control-box,
.tips-list,
.player-list {
  scrollbar-width: thin;
  scrollbar-color: #444 transparent;
}

/* HOME SCREEN */
.home-screen {
  width: 800px;
  display: flex;
  gap: 2rem;
  background: var(--panel-bg);
  padding: 2rem;
  border-radius: 10px;
  font-size: var(--home-font-size);
}

.column {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.box {
  background: var(--card-bg);
  padding: 1rem;
  border-radius: 8px;
  border: 1px solid var(--muted-border);
}

.info-box p,
.info-box ol,
.info-box ul {
  margin-bottom: 0.8rem;
  line-height: 1.4;
}
.info-box ul {
  margin-top: 1.4rem;
  padding-left: 1.2rem;
  list-style-type: disc;
}
.info-box li {
  margin-bottom: 0.4rem;
}
.info-link {
  color: #708090;
  text-decoration: none;
}
.info-link:hover {
  text-decoration: underline;
}
.info-link span {
  text-decoration: none;
}

.controls-box input[type="text"] {
  margin-top: 1rem;
}
.controls-box .btn {
  margin-top: 0.6rem;
}
.inline-check {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin-top: 0.8rem;
}
.lobby-message {
  color: var(--accent);
  font-size: 14px;
  margin-top: 1rem;
}
.lobby-list {
  list-style: none;
  max-height: 200px;
  overflow-y: auto;
  padding-left: 0.4rem;
}
.lobby-list li {
  display: grid;
  grid-template-columns: 1fr 100px;
  border-bottom: 1px solid var(--muted-border);
  padding: 0.4rem 0;
}
.lobby-list .status-ready {
  color: var(--status-ready);
}
.lobby-list .status-not-ready {
  color: var(--status-not-ready);
}
.lobby-list .status-in-game {
  color: var(--status-in-game);
}

/* CANVAS WRAPPER */
#canvasWrapper {
  display: flex; /* Default state when not hidden */
  width: 100vw;
  height: 100vh;
  justify-content: center;
  align-items: flex-start;
  padding: 1rem;
}
.main-panel {
  display: flex;
  gap: var(--panel-gap);
  align-items: stretch;
}
.sidebar,
.chat-box {
  width: 260px;
  height: calc(var(--canvas-height) + 128px);
  background: var(--panel-bg);
  padding: 1rem;
  border-right: 1px solid var(--muted-border);
  display: flex;
  flex-direction: column;
  gap: 0.8rem;
  font-size: var(--left-panel-font-size);
}
.sidebar {
  width: 240px;
  margin-right: 0.5rem;
}
.chat-box {
  margin-left: 0.5rem;
  border-right: none;
  border-left: 1px solid var(--muted-border);
}
.sidebar .box h3,
.chat-box h3 {
  margin-bottom: 0.6rem;
  color: #aaa;
  font-size: 1rem;
}
.sidebar .box:last-child {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-height: 0;
}
.sidebar .box:has(.tips-list) {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-height: 0; /* allows children to shrink */
}

.player-list {
  list-style: none;
  height: calc(var(--canvas-height) * 0.3);
  overflow-y: auto;
  padding-left: 0;
}
.player-list li {
  border-bottom: 1px solid var(--muted-border);
  padding: 0.45rem;
  min-height: 36px;
}
.player-list li:last-child {
  border-bottom: none;
}
.votes-grid {
  display: grid;
  grid-template-columns: 1fr 44px;
  row-gap: 6px;
  column-gap: 8px;
  align-items: center;
  font-size: inherit;
}
.votes-grid input[type="checkbox"] {
  justify-self: center;
  transform: scale(0.98);
}
.copy-map-row {
  margin-top: 8px;
}
.tips-list {
  flex: 1;
  line-height: 1.5;
  padding-left: 1.1rem;
  overflow-y: auto;
  min-height: 0;
}
.hotkey-desc {
  font-size: 0.85em;
  color: #ccc;
}
.canvas-area {
  display: flex;
  justify-content: center;
  align-items: flex-start;
}
.canvas-frame {
  width: var(--canvas-width);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
}
canvas {
  width: 100%;
  height: auto;
  background: #1e1e1e;
  border: 2px solid #444;
  box-shadow: 0 0 10px rgba(0, 0, 0, 0.5);
  display: block;
}

/* CONTROL BOX & DYNAMIC EDITOR */
.control-box {
  background: var(--card-bg);
  padding: 0.9rem;
  padding-top: 0.1rem;
  border-radius: 8px;
  width: 100%;
  height: 115px;
  overflow-y: auto;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.6rem;
  border: 1px solid var(--muted-border);
  font-size: 13px;
}
.control-box #status {
  width: 100%;
  text-align: center;
  font-size: 13px;
  white-space: nowrap;
}
.editor-container {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: 30px;
  width: 100%;
  padding: 8px;
  padding-bottom: 0px;
}
.editor-col {
  flex: 1; /* Makes columns equal width */
  display: flex;
  flex-direction: column;
  gap: 8px; /* Space between rows */
}

.editor-col-left {
  display: flex;
  flex-direction: column;
  gap: 10px;
  padding-top: 0px;
}
.editor-col-right {
  display: flex;
  flex-direction: column;
  gap: 3px;
  flex: 1;
}
.editor-row {
  display: flex;
  align-items: center;
  justify-content: left;
  gap: 8px;
}
.editor-row .btn,
.editor-row select {
  flex: 1;
  width: 100%;
  height: 26px;
  padding: 4px 8px;
  font-size: 12px;
  min-width: 115px;
}
.slider-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  width: 100%;
  margin-bottom: 1px;
}
.slider-row label {
  width: 55px;
  flex-shrink: 0;
  text-align: left;
  font-size: 12px;
}
.slider-row label small {
  font-size: 10px;
  opacity: 0.7;
}
.slider-row input[type="range"] {
  flex: 1;
  flex-grow: 1;
  height: 24px;
  margin: 0px;
}
.slider-row .slider-value {
  flex-basis: 30px;
  flex-shrink: 0;
  width: 20px;
  text-align: right;
  font-size: 12px;
}

/* Dynamic Editor State Management */
/* Hide all specific control groups by default */
.line-controls,
.poly-controls,
.circle-controls {
  display: none;
}

/* Show the relevant controls based on the data attribute on the parent */
.control-box[data-editor-mode="line"] .line-controls {
  display: flex;
}
.control-box[data-editor-mode="poly"] .poly-controls {
  display: flex;
}
.control-box[data-editor-mode="circle"] .circle-controls {
  display: flex;
}

/* Show the status text ONLY when no specific editor is active */
.control-box:not([data-editor-mode="line"]):not([data-editor-mode="poly"]):not([data-editor-mode="circle"])
  #status {
  display: block;
}

/* Hide the status text when ANY editor is active */
.control-box[data-editor-mode="line"] #status,
.control-box[data-editor-mode="poly"] #status,
.control-box[data-editor-mode="circle"] #status {
  display: none;
}

/* CHAT */
#chatMessages {
  background: var(--card-bg);
  padding: 0.6rem;
  border-radius: 6px;
  overflow-y: auto;
  height: calc(var(--canvas-height) - 40px);
  border: 1px solid var(--muted-border);
  font-size: 13px;
}
#chatMessages > * {
  border-bottom: 1px solid var(--muted-border);
  padding-bottom: 4px;
  margin-bottom: 4px;
}
#chatMessages > *:last-child {
  border-bottom: none;
}
#chatMessages p {
  margin: 0.25rem 0;
  word-wrap: break-word;
}
#chatInput {
  padding: 0.45rem;
}
#chatSendBtn {
  align-self: flex-end;
}
.chat-sender {
  color: #bbb;
  font-weight: 600;
  margin-right: 4px;
}
.chat-error {
  color: var(--status-not-ready);
  font-style: italic;
}

/* POPUP */
.popup-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.85);
  display: flex; /* Default state when not hidden */
  justify-content: center;
  align-items: center;
  z-index: 999;
}
.popup-box {
  position: relative;
  background: var(--panel-bg);
  padding: 1.5rem;
  border-radius: 10px;
  text-align: center;
  width: 360px;
  border: 1px solid var(--muted-border);
}
.popup-box h2 {
  margin-bottom: 0.6rem;
}
.popup-box p {
  margin-bottom: 1rem;
  color: #ddd;
}
.popup-close {
  position: absolute;
  top: 8px;
  right: 8px;
  background: none;
  color: #fff;
  font-size: 1.1rem;
  border: none;
  cursor: pointer;
  padding: 0;
}
.popup-actions {
  display: flex;
  gap: 8px;
  justify-content: center;
}
.popup-actions .btn {
  padding: 0.5rem 0.9rem;
}

/* ADMIN PANEL */
.admin-panel {
  position: fixed;
  top: 1rem;
  right: 1rem;
  z-index: 1000;
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  margin-top: 0px;
  margin-right: -14px
}
.admin-panel-toggle {
  background: var(--card-bg);
  border: 1px solid var(--muted-border);
  color: white !important; /* force white */
  padding: 0.5rem 0.8rem;
  border-radius: 5px;
  cursor: pointer;
  font-size: 1rem;
}
.admin-panel-toggle:hover {
    background: #444;
}
.admin-panel-content {
  background: var(--panel-bg);
  border: 1px solid var(--muted-border);
  border-radius: 8px;
  padding: 1rem;
  margin-top: 0.5rem;
  width: 280px;
  display: flex;
  flex-direction: column;
  gap: 1rem;
}
.admin-login-form {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}
.admin-login-form input, .admin-section input {
  font-size: 13px;
  margin-bottom: 0.5rem;
}
.admin-login-form .btn, .admin-section .btn {
  width: 100%;
}
.admin-section h4 {
  margin-bottom: 0.5rem;
  border-bottom: 1px solid var(--muted-border);
  padding-bottom: 0.3rem;
  color: #ccc;
  font-size: 1rem;
}
.admin-player-list {
  list-style: none;
  max-height: 150px;
  overflow-y: auto;
  padding: 0;
  scrollbar-width: thin;
  scrollbar-color: #444 transparent;
}
.admin-player-list::-webkit-scrollbar { width: 7px; }
.admin-player-list::-webkit-scrollbar-thumb { background: #444; border-radius: 4px; }
.admin-player-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 5px 2px;
  font-size: 13px;
  border-bottom: 1px solid var(--muted-border);
}
.admin-player-item:last-child {
    border-bottom: none;
}
.admin-player-actions .btn {
  padding: 3px 8px;
  font-size: 12px;
}

/* Add style for the dynamically created lobby password input */
#lobbyPasswordInput {
  margin-top: 1rem;
  margin-bottom: 0.6rem;
}

#lobbyPasswordInput, #adminPasswordInput {
  font-size: 13px;
  margin-bottom: 0.5rem;
  padding: 0.4rem 0.6rem;
  border: 1px solid var(--muted-border);
  border-radius: 5px;
  background: var(--card-bg);
  color: #eee;
  width: 100%;
  font-family: "Lexend", sans-serif;"
}

/* Add these to your style.css */

.popup-box form {
  margin-top: 1rem;
}

.popup-form-row {
  display: grid;
  grid-template-columns: 1fr 100px; /* Label | Input */
  gap: 10px;
  align-items: center;
  margin-bottom: 12px;
}

.popup-form-row label {
  text-align: left;
  font-size: 13px;
  color: #ccc;
}

.popup-form-row input[type="number"] {
  width: 100%; /* Fill the 100px column */
  padding: 0.4rem;
  font-size: 13px;
  background: #1e1e1e;
  color: #eee;
  border: 1px solid #444;
  border-radius: 4px;
}

.weights-label {
  display: block;
  text-align: left;
  font-size: 13px;
  color: #ccc;
  margin-bottom: 8px;
}

.weights-row {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  gap: 10px;
  text-align: center;
  margin-bottom: 12px;
}
.weights-row label {
  text-align: center;
  font-size: 12px;
  margin-bottom: 4px;
  display: block;
  color: #aaa;
}
.weights-row input[type="number"] {
  width: 100%;
}

.popup-box .btn {
  margin-top: 1rem;
  width: 100%;
}
.color-indicators-container {
    display: flex;
    justify-content: center;
    gap: 20px;
    padding: 8px 0;
    font-size: 12px;
}
.color-indicator {
    display: flex;
    align-items: center;
    gap: 6px;
}
.color-square {
    width: 14px;
    height: 14px;
    border: 1px solid #666;
    border-radius: 2px;
    display: inline-block;
}

/* RESPONSIVE */
@media (max-width: 1200px) {
  .main-panel {
    flex-direction: column;
    align-items: center;
    gap: 1rem;
  }
  .sidebar,
  .chat-box {
    width: 90%;
    max-width: 340px;
    height: auto;
  }
  .canvas-frame {
    width: min(90vw, var(--canvas-width));
  }
}

