  if (key === "m") {
    const btn = UI.elems.drawModeBtn;
    if (btn) btn.click();
    return;
  }
  if (key === "g") {
    e.preventDefault();
    UI.show("autoGeneratePopup");
    return;
  }
  // General hotkeys
  switch (key) {
    case "enter":
      if (document.activeElement !== UI.elems.chatInput) {
        e.preventDefault();
        UI.elems.chatInput.focus();
      }
      return;
    case "a":
      if (e.ctrlKey) {
        e.preventDefault();
