  // hook it up once
  safeAddEvent(e.typeSelect, "change", createSelectHandler());

  safeAddEvent(e.typeSelect, "change", createSelectHandler());

  const createDeleteHandler = () => () => {
    const selectedIds = State.get("selectedObjectIds");
    if (selectedIds.length > 0) {
      selectedIds.forEach((id) => Network.deleteObject(id));
